changeSet.sql:
create table chat.user_session ( user_id varchar, instance_id varchar, created_at timestamp, primary key ((user_id)) );
create table chat.p2p_room ( room_id varchar, created_at timestamp, message_id timeuuid, modified_at timestamp, content text, sender_id varchar, receiver_id varchar, is_delivered boolean, is_read boolean, primary key ((room_id), message_id) ) with clustering order by (message_id desc);
create table chat.contacts_by_user ( user_id varchar, contact_id varchar, is_blocked boolean, is_favourite boolean, tags set<text>, primary key ((user_id), contact_id) ) with clustering order by (contact_id asc);
